import React from 'react';
import Navbar from '../../components/common/Navbar';
import Sidebar from '../../components/common/Sidebar';
import Card from '../../components/common/Card';
import DriftChart from '../../components/charts/DriftChart';
import BarChart from '../../components/charts/BarChart';

const InstructorDashboard = () => {
  const userName = localStorage.getItem('userName') || 'Instructor';

  const driftTrendData = {
    labels: ['Week 1', 'Week 2', 'Week 3', 'Week 4'],
    datasets: [{
      label: 'Average Drift Score',
      data: [0.35, 0.42, 0.38, 0.45],
      borderColor: 'rgb(239, 68, 68)',
      backgroundColor: 'rgba(239, 68, 68, 0.5)',
    }],
  };

  const weakAreasData = {
    labels: ['Arrays', 'Strings', 'Trees', 'DBMS', 'OS'],
    datasets: [{
      label: 'Students Struggling',
      data: [12, 8, 15, 6, 10],
      backgroundColor: ['#ef4444', '#f59e0b', '#3b82f6', '#10b981', '#8b5cf6'],
    }],
  };

  const recentAlerts = [
    { student: 'Asha', topic: 'Recursion', score: 0.89, level: 'High' },
    { student: 'Ravi', topic: 'Arrays', score: 0.82, level: 'High' },
    { student: 'Teja', topic: 'Loops', score: 0.41, level: 'Medium' },
  ];

  const studentsNeedingAttention = [
    { name: 'Asha', accuracy: '45%', drift: 0.89, status: 'High' },
    { name: 'Ravi', accuracy: '52%', drift: 0.82, status: 'High' },
    { name: 'Priya', accuracy: '68%', drift: 0.65, status: 'Medium' },
  ];

  return (
    <div className="min-h-screen bg-gray-100">
      <Navbar role="Instructor" userName={userName} />
      <div className="flex">
        <Sidebar role="instructor" />
        <main className="flex-1 p-6">
          <h2 className="text-3xl font-bold text-gray-800 mb-6">Instructor Dashboard</h2>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6 mb-6">
            <Card title="Total Students" value="156" icon="👥" color="blue" />
            <Card title="Active Students" value="142" icon="✅" color="green" />
            <Card title="High Drift" value="18" icon="⚠️" color="red" />
            <Card title="Total Alerts" value="34" icon="🔔" color="yellow" />
            <Card title="Avg Drift Score" value="0.42" icon="📊" color="purple" />
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
            <div className="bg-white rounded-lg shadow p-6">
              <DriftChart data={driftTrendData} title="Drift Trend Over Time" />
            </div>
            <div className="bg-white rounded-lg shadow p-6">
              <BarChart data={weakAreasData} title="Topic-wise Weak Areas" />
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <div className="bg-white rounded-lg shadow p-6">
              <h3 className="text-xl font-semibold mb-4">Recent Alerts</h3>
              <div className="space-y-3">
                {recentAlerts.map((alert, index) => (
                  <div key={index} className={`p-4 rounded-lg border-l-4 ${
                    alert.level === 'High' ? 'border-red-500 bg-red-50' : 'border-yellow-500 bg-yellow-50'
                  }`}>
                    <div className="flex justify-between items-start">
                      <div>
                        <p className="font-semibold text-gray-800">{alert.student}</p>
                        <p className="text-sm text-gray-600">Topic: {alert.topic}</p>
                      </div>
                      <div className="text-right">
                        <p className="font-semibold text-red-600">{alert.score}</p>
                        <p className="text-xs text-gray-600">{alert.level} Risk</p>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="bg-white rounded-lg shadow p-6">
              <h3 className="text-xl font-semibold mb-4">Students Needing Attention</h3>
              <div className="space-y-3">
                {studentsNeedingAttention.map((student, index) => (
                  <div key={index} className="flex justify-between items-center border-b pb-3">
                    <div>
                      <p className="font-semibold text-gray-800">{student.name}</p>
                      <p className="text-sm text-gray-600">Accuracy: {student.accuracy}</p>
                    </div>
                    <div className="text-right">
                      <p className="font-semibold text-red-600">Drift: {student.drift}</p>
                      <span className={`text-xs px-2 py-1 rounded-full ${
                        student.status === 'High' ? 'bg-red-200 text-red-800' : 'bg-yellow-200 text-yellow-800'
                      }`}>
                        {student.status}
                      </span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default InstructorDashboard;
